INSERT INTO "registration_authorities" ("authority_id","authority_key","authority_name","authority_abbreviation","country","sector","website_url","cpd_platform_url","uses_hours","uses_points","uses_ceus","uses_credits","unit_label","units_per_hour","split_label","split_bar_concept","ui_labels","mandatory_topics_enabled","cpd_term","cpd_term_full","created_at","updated_at") VALUES ('8804383b-6eb9-4580-8fba-ca36565af4fc','us_ar_asbde','Arkansas State Board of Dental Examiners','ASBDE','US','dental','https://www.asbde.org',NULL,1,0,0,0,'CEUs',1,'Live / Online','none','{"programme_label":"CE","unit_singular":"CEU","unit_plural":"CEUs","unit_short":"CEUs","split_label_positive":"Live / In-person","split_label_negative":"Home study / Online","split_min_label":"No live minimum — 100% online allowed","cap_warning_label":"","deficit_message":"You need {n} more CEUs","reflection_label":"Record (typed list signed; retain 3 yrs)","notes":"1 CEU = 50 min. Biennial cycle: 1 Jan even-year – 31 Dec odd-year. 100% home study/online allowed — no live minimum. No carry-over. 17 CAR §§ 115-1401 to 115-1410."}',1,'CE','Continuing Education','2026-03-23 21:03:47','2026-03-23 21:03:47');
INSERT INTO "registration_authorities" ("authority_id","authority_key","authority_name","authority_abbreviation","country","sector","website_url","cpd_platform_url","uses_hours","uses_points","uses_ceus","uses_credits","unit_label","units_per_hour","split_label","split_bar_concept","ui_labels","mandatory_topics_enabled","cpd_term","cpd_term_full","created_at","updated_at") VALUES ('6e22e8ea-2e55-4a99-8f5a-d9ab04de1578','us_ca_dbc','Dental Board of California','DBC','US','dental','https://www.dbc.ca.gov',NULL,1,0,0,0,'CEUs',1,'Core / Non-core','structured','{"programme_label":"CE","unit_singular":"CEU","unit_plural":"CEUs","unit_short":"CEUs","split_label_positive":"Core subjects (clinical/scientific)","split_label_negative":"Non-core subjects","split_min_label":"Minimum 80% core subjects required","cap_warning_label":"Non-core cap (20%)","deficit_message":"You need {n} more CEUs","reflection_label":"Record (self-attestation; retain 6 yrs / 3 renewal periods)","notes":"1 CEU = 50 min. Birth-month biennial cycle. 50% max home study/online. Max 8 units/day. First renewal fully exempt. 16 CCR §§ 1015-1017.2. Dentists: mandatory Infection Control (2u), Dental Practice Act (2u), BLS live (4u max), Schedule II opioids (2u)."}',1,'CE','Continuing Education','2026-03-23 21:03:47','2026-03-23 21:03:47');
INSERT INTO "registration_authorities" ("authority_id","authority_key","authority_name","authority_abbreviation","country","sector","website_url","cpd_platform_url","uses_hours","uses_points","uses_ceus","uses_credits","unit_label","units_per_hour","split_label","split_bar_concept","ui_labels","mandatory_topics_enabled","cpd_term","cpd_term_full","created_at","updated_at") VALUES ('98adb6ca-e820-4424-aab1-dd149bf236ec','us_ca_dhbc','Dental Hygiene Board of California','DHBC','US','dental','https://www.dhbc.ca.gov',NULL,1,0,0,0,'CEUs',1,'Live / Online','structured','{"programme_label":"CE","unit_singular":"CEU","unit_plural":"CEUs","unit_short":"CEUs","split_label_positive":"Live / structured CE","split_label_negative":"Home study / Online","split_min_label":"50% must be live/structured","cap_warning_label":"Online cap (50%)","deficit_message":"You need {n} more CEUs","reflection_label":"Record (self-attestation; retain 6 yrs)","notes":"1 CEU = 50 min. Birth-month biennial cycle. 50% max home study/online (12.5u RDH, 17.5u RDHAP). First renewal fully exempt. 16 CCR §§ 1015-1017. RDH: Infection Control, DPA, BLS mandatory. RDHAP: 35 CE units/cycle."}',1,'CE','Continuing Education','2026-03-23 21:03:47','2026-03-23 21:03:47');
INSERT INTO "registration_authorities" ("authority_id","authority_key","authority_name","authority_abbreviation","country","sector","website_url","cpd_platform_url","uses_hours","uses_points","uses_ceus","uses_credits","unit_label","units_per_hour","split_label","split_bar_concept","ui_labels","mandatory_topics_enabled","cpd_term","cpd_term_full","created_at","updated_at") VALUES ('33083947-b356-4136-8520-c824f4b809ad','us_co_cdb','Colorado Dental Board','CDB','US','dental','https://dora.colorado.gov/dental',NULL,1,0,0,0,'CE hours',1,'Live / Online','structured','{"programme_label":"CE","unit_singular":"CE hour","unit_plural":"CE hours","unit_short":"CE hrs","split_label_positive":"Live & interactive CE (in-person or live webinar)","split_label_negative":"Online/home-study (non-interactive)","split_min_label":"Min 15 hrs live/interactive (50%)","cap_warning_label":"Online/home-study cap (50% = 15 hrs)","deficit_message":"You need {n} more CE hours","reflection_label":"Record (self-attestation DORA renewal; retain 4 yrs / 2 periods)","notes":"1 CE hr = 60 min. Fixed biennial: 28 Feb even years. 50% online cap (15/30 hrs). Max 2 hrs BLS credited. Max 6 hrs presenter credit. First renewal: ≤12 months since registration → 0 CE exempt; >12 months → 15 hrs pro-rata (8 clinical min). Disciplinary CE excluded. Academic Dentist ineligible for inactive/retired. 3 CCR 709-1, Rule 1.6(H)."}',1,'CE','Continuing Education','2026-03-23 21:03:47','2026-03-23 21:03:47');
INSERT INTO "registration_authorities" ("authority_id","authority_key","authority_name","authority_abbreviation","country","sector","website_url","cpd_platform_url","uses_hours","uses_points","uses_ceus","uses_credits","unit_label","units_per_hour","split_label","split_bar_concept","ui_labels","mandatory_topics_enabled","cpd_term","cpd_term_full","created_at","updated_at") VALUES ('298ff801-c91a-4fca-b6ec-37c42032d486','us_ct_dph_dental','Connecticut Dept. of Public Health — Dental','CT-DPH (Dental)','US','dental','https://portal.ct.gov/dph/practitioner-licensing--investigations/dental',NULL,1,0,0,0,'contact hours',1,'Live / Online','structured','{"programme_label":"CE","unit_singular":"contact hour","unit_plural":"contact hours","unit_short":"hrs","split_label_positive":"Live / interactive CE (Dentist — unlimited; RDH min 75%)","split_label_negative":"Online / distance learning","split_min_label":"RDH: max 4 hrs (25%) online; self-study excluded. Dentist: 100% online permitted.","cap_warning_label":"RDH online cap (25% = 4 hrs); self-study not permitted for RDH","deficit_message":"You need {n} more contact hours","reflection_label":"Record (self-attestation DPH renewal; retain 3 years)","notes":"1 contact hour = 50 min. Annual birth-month renewal; 24-month rolling CE window. First renewal fully exempt. Dentist: 25 hrs / 24-month window, 100% online permitted. RDH: 16 hrs / 24-month, max 4 hrs (25%) online, no self-study, max 8 hrs/day, max 5 volunteer hrs. Disciplinary CE excluded. Void reinstatement: dentist 12 hrs (1 yr window); RDH <2 yrs = 24 hrs; RDH >2 yrs = board exam. CGS §§ 20-126c, 20-111c."}',1,'CE','Continuing Education','2026-03-23 21:03:47','2026-03-23 21:03:47');
INSERT INTO "registration_authorities" ("authority_id","authority_key","authority_name","authority_abbreviation","country","sector","website_url","cpd_platform_url","uses_hours","uses_points","uses_ceus","uses_credits","unit_label","units_per_hour","split_label","split_bar_concept","ui_labels","mandatory_topics_enabled","cpd_term","cpd_term_full","created_at","updated_at") VALUES ('da079ccd-684e-4654-8f9f-967f58679dd5','us_de_bddhd','Delaware Board of Dentistry and Dental Hygiene','DE-BDDHD','US','dental','https://dpr.delaware.gov/boards/dental/',NULL,1,0,0,0,'CPE credit hours',1,'Live / Self-Study','structured','{"programme_label":"CPE","unit_singular":"CPE credit hour","unit_plural":"CPE credit hours","unit_short":"hrs","split_label_positive":"Live / interactive CPE","split_label_negative":"Self-study (Type A + Type B)","split_min_label":"Dentist: max 30 hrs self-study (10 no-test + 20 with-test). RDH: max 10 hrs (5+5). CPR required separately — earns 0 CPE.","cap_warning_label":"Self-study cap (Type A + Type B combined) — dentist 30 / RDH 10 hrs","deficit_message":"You need {n} more CPE credit hours","reflection_label":"Record in DELPROS; retain certificates for audit","notes":"1 CPE = 50 min. Biennial: Jun 1 – May 31, even years. Dentist: 50 hrs (incl. 2 IC mandatory, CPR required non-CPE). RDH: 24 hrs (incl. 2 IC mandatory, CPR required non-CPE). Type A no-test cap: 10 DDS/5 RDH. Combined A+B cap: 30 DDS/10 RDH. Pro-rata: <12 months = 0; 12–24 months = 50%. CE entered in DELPROS. 24 Del. Admin. Code § 1100-6.0."}',1,'CPE','Continuing Professional Education','2026-03-23 21:03:47','2026-03-23 21:03:47');
INSERT INTO "registration_authorities" ("authority_id","authority_key","authority_name","authority_abbreviation","country","sector","website_url","cpd_platform_url","uses_hours","uses_points","uses_ceus","uses_credits","unit_label","units_per_hour","split_label","split_bar_concept","ui_labels","mandatory_topics_enabled","cpd_term","cpd_term_full","created_at","updated_at") VALUES ('78928819-9a96-4cf7-bc08-053ea531c5b6','_hidden_de_bvm','[Removed duplicate] Delaware BVM','DE-BVM','US','veterinary','https://dpr.delaware.gov/boards/veterinarymedicine/',NULL,1,0,0,0,'CE credit hours',1,'Clinical / Non-Clinical','none','{"programme_label":"CE","unit_singular":"CE credit hour","unit_plural":"CE credit hours","unit_short":"hrs","split_label_positive":"Vet-relevant CE","split_label_negative":"N/A","split_min_label":"100% online/distance learning permitted (RACE / Board-approved)","cap_warning_label":"N/A","deficit_message":"You need {n} more CE credit hours","reflection_label":"Record in DELPROS; retain certificates for audit","notes":"1 CE = 50 min. Biennial: Aug 1 (even) – Jul 31 (odd). DVM: 24 hrs. VT: 12 hrs. 100% RACE/Board online. 4-bracket pro-rata (Aug even–Jul odd = 12/6 hrs; Aug odd–Jan even = 6/3; Feb–Mar even = 0; Apr even+ = full). Pre-graduation coursework eligible first renewal (within 2.5 yrs). Extension request ≥60 days before expiry. CSR holders: 2-hr CE per CSR cycle (30 Jun odd). 24 Del. Admin. Code § 3300-10.0, 15.0."}',0,'CE','Continuing Education','2026-03-23 21:03:47','2026-03-23 21:03:47');
